     1→/**
     2→ * Markdown Export Utilities
     3→ *
     4→ * Converts notes and tasks to portable markdown format with wiki link preservation,
     5→ * folder structure support, and ZIP export capabilities.
     6→ */
     7→
     8→import JSZip from 'jszip';
     9→import {
    10→  $convertToMarkdownString,
    11→  TRANSFORMERS,
    12→} from '@lexical/markdown';
    13→import { createEditor } from 'lexical';
    14→import { logger } from '../services/logger';
    15→import type { Note, Folder } from '../types/notes';
    16→import type { Task } from '../types';
    17→
    18→const log = logger.module('MarkdownExport');
    19→
    20→// ==================== TASK 1: LEXICAL-TO-MARKDOWN CONVERTER ====================
    21→
    22→/**
    23→ * Export note to markdown format with frontmatter
    24→ *
    25→ * Converts Lexical JSON content to markdown while preserving wiki links and metadata.
    26→ * Adds YAML frontmatter with note metadata (title, dates, tags, folder, etc.)
    27→ */
    28→export function exportNoteToMarkdown(
    29→  note: Note,
    30→  _allNotes: Record<string, Note>,
    31→  folders?: Folder[]
    32→): string {
    33→  try {
    34→    // Parse Lexical content
    35→    let markdownContent = '';
    36→
    37→    if (note.content) {
    38→      try {
    39→        // Create a temporary editor to convert Lexical state to markdown
    40→        const editor = createEditor({
    41→          onError: (error) => {
    42→            log.error('Lexical editor error during markdown conversion', { error });
    43→          },
    44→        });
    45→
    46→        editor.update(() => {
    47→          const parsedContent = JSON.parse(note.content);
    48→          const editorState = editor.parseEditorState(parsedContent);
    49→          editor.setEditorState(editorState);
    50→        });
    51→
    52→        // Convert to markdown using Lexical transformers
    53→        editor.getEditorState().read(() => {
    54→          markdownContent = $convertToMarkdownString(TRANSFORMERS);
    55→        });
    56→      } catch (error) {
    57→        log.warn('Failed to parse Lexical content, using plain text', { error });
    58→        markdownContent = note.contentText || '';
    59→      }
    60→    } else {
    61→      // Fallback to plain text if no Lexical content
    62→      markdownContent = note.contentText || '';
    63→    }
    64→
    65→    // Build frontmatter
    66→    const frontmatter = buildFrontmatter(note, folders);
    67→
    68→    // Combine frontmatter + content
    69→    return `${frontmatter}\n${markdownContent}`;
    70→  } catch (error) {
    71→    log.error('Error exporting note to markdown', { noteId: note.id, error });
    72→    throw error;
    73→  }
    74→}
    75→
    76→/**
    77→ * Build YAML frontmatter from note metadata
    78→ */
    79→function buildFrontmatter(note: Note, folders?: Folder[]): string {
    80→  const metadata: Record<string, any> = {
    81→    title: note.title,
    82→    created: note.createdAt.toISOString(),
    83→    updated: note.updatedAt.toISOString(),
    84→  };
    85→
    86→  // Add tags if present
    87→  if (note.tags && note.tags.length > 0) {
    88→    metadata.tags = note.tags;
    89→  }
    90→
    91→  // Resolve folder name if folderId exists
    92→  if (note.folderId && folders) {
    93→    const folder = folders.find((f) => f.id === note.folderId);
    94→    if (folder) {
    95→      metadata.folder = folder.name;
    96→    }
    97→  }
    98→
    99→  // Add optional fields
   100→  if (note.isPinned) metadata.pinned = true;
   101→  if (note.isFavorite) metadata.favorite = true;
   102→  if (note.color) metadata.color = note.color;
   103→  if (note.icon) metadata.icon = note.icon;
   104→
   105→  // Convert to YAML format
   106→  const yamlLines = ['---'];
   107→  Object.entries(metadata).forEach(([key, value]) => {
   108→    if (Array.isArray(value)) {
   109→      yamlLines.push(`${key}: [${value.map((v) => JSON.stringify(v)).join(', ')}]`);
   110→    } else if (typeof value === 'string' && value.includes(':')) {
   111→      // Quote strings with colons to avoid YAML parsing issues
   112→      yamlLines.push(`${key}: "${value}"`);
   113→    } else {
   114→      yamlLines.push(`${key}: ${JSON.stringify(value)}`);
   115→    }
   116→  });
   117→  yamlLines.push('---');
   118→
   119→  return yamlLines.join('\n');
   120→}
   121→
   122→/**
   123→ * Generate markdown-safe filename from note title
   124→ *
   125→ * Sanitizes title for filesystem compatibility:
   126→ * - Removes special characters: < > : " / \ | ? *
   127→ * - Replaces spaces with hyphens
   128→ * - Truncates to 255 characters (filesystem limit)
   129→ * - Adds .md extension
   130→ */
   131→export function getMarkdownFilename(note: Note): string {
   132→  let filename = note.title;
   133→
   134→  // Replace special filesystem characters
   135→  filename = filename.replace(/[<>:"/\\|?*]/g, '');
   136→
   137→  // Replace spaces with hyphens
   138→  filename = filename.replace(/\s+/g, '-');
   139→
   140→  // Remove leading/trailing hyphens
   141→  filename = filename.replace(/^-+|-+$/g, '');
   142→
   143→  // Truncate to 255 chars (leave room for .md extension)
   144→  filename = filename.substring(0, 250);
   145→
   146→  // Fallback if empty after sanitization
   147→  if (!filename) {
   148→    filename = `note-${note.id.substring(0, 8)}`;
   149→  }
   150→
   151→  return `${filename}.md`;
   152→}
   153→
   154→/**
   155→ * Validate markdown content
   156→ *
   157→ * Checks if markdown string is valid:
   158→ * - Non-empty content beyond frontmatter
   159→ * - Frontmatter parses correctly
   160→ */
   161→export function isValidMarkdown(markdown: string): boolean {
   162→  if (!markdown || markdown.trim().length === 0) {
   163→    return false;
   164→  }
   165→
   166→  // Check for frontmatter
   167→  const frontmatterMatch = markdown.match(/^---\n([\s\S]*?)\n---/);
   168→  if (!frontmatterMatch) {
   169→    // No frontmatter is okay, just needs content
   170→    return markdown.trim().length > 0;
   171→  }
   172→
   173→  // Validate frontmatter YAML (basic check)
   174→  const frontmatter = frontmatterMatch[1];
   175→  try {
   176→    // Check for basic YAML structure (key: value pairs)
   177→    const lines = frontmatter.split('\n');
   178→    for (const line of lines) {
   179→      if (line.trim() && !line.includes(':')) {
   180→        return false; // Invalid YAML line
   181→      }
   182→    }
   183→  } catch {
   184→    return false;
   185→  }
   186→
   187→  // Check for content beyond frontmatter
   188→  const content = markdown.substring(frontmatterMatch[0].length).trim();
   189→  return content.length > 0;
   190→}
   191→
   192→// ==================== TASK 2: TASK-TO-MARKDOWN FORMATTER ====================
   193→
   194→/**
   195→ * Export single task to markdown with frontmatter and metadata
   196→ */
   197→export function exportTaskToMarkdown(task: Task): string {
   198→  // Build frontmatter
   199→  const frontmatter = buildTaskFrontmatter(task);
   200→
   201→  // Build task body
   202→  const body = buildTaskBody(task);
   203→
   204→  return `${frontmatter}\n${body}`;
   205→}
   206→
   207→/**
   208→ * Build YAML frontmatter for task
   209→ */
   210→function buildTaskFrontmatter(task: Task): string {
   211→  const metadata: Record<string, any> = {
   212→    title: task.title,
   213→    status: task.status,
   214→    priority: task.priority,
   215→    created: task.created,
   216→  };
   217→
   218→  // Add dates if present
   219→  if (task.startDate) metadata['start-date'] = task.startDate;
   220→  if (task.dueDate) metadata['due-date'] = task.dueDate;
   221→
   222→  // Add tags
   223→  if (task.tags && task.tags.length > 0) {
   224→    metadata.tags = task.tags;
   225→  }
   226→
   227→  // Add card number if present
   228→  if (task.cardNumber) {
   229→    metadata['card-number'] = `KAN-${task.cardNumber}`;
   230→  }
   231→
   232→  // Convert to YAML
   233→  const yamlLines = ['---'];
   234→  Object.entries(metadata).forEach(([key, value]) => {
   235→    if (Array.isArray(value)) {
   236→      yamlLines.push(`${key}: [${value.map((v) => JSON.stringify(v)).join(', ')}]`);
   237→    } else if (value === null) {
   238→      yamlLines.push(`${key}: null`);
   239→    } else if (typeof value === 'string' && value.includes(':')) {
   240→      yamlLines.push(`${key}: "${value}"`);
   241→    } else {
   242→      yamlLines.push(`${key}: ${JSON.stringify(value)}`);
   243→    }
   244→  });
   245→  yamlLines.push('---');
   246→
   247→  return yamlLines.join('\n');
   248→}
   249→
   250→/**
   251→ * Build task body with description, checklist, metadata
   252→ */
   253→function buildTaskBody(task: Task): string {
   254→  const sections: string[] = [];
   255→
   256→  // Description
   257→  if (task.description) {
   258→    sections.push('## Description\n');
   259→    sections.push(task.description + '\n');
   260→  }
   261→
   262→  // Checklist
   263→  if (task.checklist && task.checklist.length > 0) {
   264→    sections.push('## Checklist\n');
   265→    task.checklist
   266→      .sort((a, b) => a.order - b.order)
   267→      .forEach((item) => {
   268→        const checkbox = item.completed ? '[x]' : '[ ]';
   269→        sections.push(`- ${checkbox} ${item.text}`);
   270→      });
   271→    sections.push('');
   272→  }
   273→
   274→  // Subtasks
   275→  if (task.subtasks && task.subtasks.length > 0) {
   276→    sections.push('## Subtasks\n');
   277→    task.subtasks
   278→      .sort((a, b) => a.order - b.order)
   279→      .forEach((subtask) => {
   280→        const checkbox = subtask.completed ? '[x]' : '[ ]';
   281→        sections.push(`- ${checkbox} ${subtask.title}`);
   282→        if (subtask.description) {
   283→          sections.push(`  ${subtask.description}`);
   284→        }
   285→      });
   286→    sections.push('');
   287→  }
   288→
   289→  // Comments
   290→  if (task.comments && task.comments.length > 0) {
   291→    sections.push('## Comments\n');
   292→    task.comments.forEach((comment) => {
   293→      const date = new Date(comment.createdAt).toLocaleString();
   294→      sections.push(`**${comment.author}** (${date}):`);
   295→      sections.push(comment.text + '\n');
   296→    });
   297→  }
   298→
   299→  // Metadata section
   300→  sections.push('## Metadata\n');
   301→  sections.push(`- **Status:** ${formatStatusLabel(task.status)}`);
   302→  sections.push(`- **Priority:** ${formatPriorityLabel(task.priority)}`);
   303→  sections.push(`- **Created:** ${formatDate(task.created)}`);
   304→
   305→  if (task.startDate) {
   306→    sections.push(`- **Start Date:** ${formatDate(task.startDate)}`);
   307→  }
   308→  if (task.dueDate) {
   309→    sections.push(`- **Due Date:** ${formatDate(task.dueDate)}`);
   310→  }
   311→  if (task.estimatedHours) {
   312→    sections.push(`- **Estimated Hours:** ${task.estimatedHours}`);
   313→  }
   314→  if (task.actualHours) {
   315→    sections.push(`- **Actual Hours:** ${task.actualHours}`);
   316→  }
   317→  if (task.progress !== undefined) {
   318→    sections.push(`- **Progress:** ${task.progress}%`);
   319→  }
   320→  if (task.assignedTo) {
   321→    sections.push(`- **Assigned To:** ${task.assignedTo}`);
   322→  }
   323→
   324→  // Dependencies
   325→  if (task.dependencies && task.dependencies.length > 0) {
   326→    sections.push('\n## Dependencies\n');
   327→    task.dependencies.forEach((dep) => {
   328→      sections.push(`- ${dep.type}: ${dep.taskId} (lag: ${dep.lag} days)`);
   329→    });
   330→  }
   331→
   332→  // Recurrence
   333→  if (task.recurrence) {
   334→    sections.push('\n## Recurrence\n');
   335→    sections.push(formatRecurrence(task.recurrence));
   336→  }
   337→
   338→  // Time tracking
   339→  if (task.timeTracking) {
   340→    sections.push('\n## Time Tracking\n');
   341→    if (task.timeTracking.estimated) {
   342→      sections.push(`- **Estimated:** ${task.timeTracking.estimated} hours`);
   343→    }
   344→    sections.push(`- **Actual:** ${task.timeTracking.actual} hours`);
   345→    if (task.timeTracking.timerHistory.length > 0) {
   346→      sections.push('\n### Timer History');
   347→      task.timeTracking.timerHistory.forEach((entry) => {
   348→        const duration = Math.round(entry.duration / 60); // Convert to minutes
   349→        sections.push(`- ${formatDate(entry.startTime)}: ${duration} minutes`);
   350→      });
   351→    }
   352→  }
   353→
   354→  // Attachments (note: data URLs not exportable)
   355→  if (task.attachments && task.attachments.length > 0) {
   356→    sections.push('\n## Attachments\n');
   357→    sections.push('*Note: File attachments contain binary data and cannot be exported to markdown. Download attachments separately.*\n');
   358→    task.attachments.forEach((att) => {
   359→      sections.push(`- ${att.filename} (${att.fileType}, ${formatFileSize(att.fileSize)})`);
   360→    });
   361→  }
   362→
   363→  return sections.join('\n');
   364→}
   365→
   366→/**
   367→ * Export multiple tasks to single markdown file (grouped by status)
   368→ */
   369→export function exportTasksToMarkdown(tasks: Task[]): string {
   370→  const sections: string[] = [];
   371→
   372→  // Title
   373→  sections.push('# Tasks Export\n');
   374→  sections.push(`*Exported on ${new Date().toLocaleString()}*\n`);
   375→
   376→  // Table of contents
   377→  sections.push('## Table of Contents\n');
   378→  const statuses: Array<'backlog' | 'todo' | 'inprogress' | 'review' | 'done'> = [
   379→    'backlog',
   380→    'todo',
   381→    'inprogress',
   382→    'review',
   383→    'done',
   384→  ];
   385→  statuses.forEach((status) => {
   386→    const count = tasks.filter((t) => t.status === status).length;
   387→    if (count > 0) {
   388→      sections.push(`- [${formatStatusLabel(status)}](#${status}) (${count} tasks)`);
   389→    }
   390→  });
   391→  sections.push('');
   392→
   393→  // Group tasks by status
   394→  statuses.forEach((status) => {
   395→    const statusTasks = tasks.filter((t) => t.status === status);
   396→    if (statusTasks.length === 0) return;
   397→
   398→    sections.push(`\n## ${formatStatusLabel(status)}\n`);
   399→
   400→    statusTasks.forEach((task) => {
   401→      sections.push(`### ${task.title}\n`);
   402→      if (task.cardNumber) {
   403→        sections.push(`**Card:** KAN-${task.cardNumber}\n`);
   404→      }
   405→      sections.push(`**Priority:** ${formatPriorityLabel(task.priority)}`);
   406→      if (task.dueDate) {
   407→        sections.push(`| **Due:** ${formatDate(task.dueDate)}`);
   408→      }
   409→      sections.push('\n');
   410→
   411→      if (task.description) {
   412→        sections.push(task.description + '\n');
   413→      }
   414→
   415→      // Checklist preview
   416→      if (task.checklist && task.checklist.length > 0) {
   417→        const completed = task.checklist.filter((i) => i.completed).length;
   418→        sections.push(`*Checklist: ${completed}/${task.checklist.length} completed*\n`);
   419→      }
   420→
   421→      sections.push('---\n');
   422→    });
   423→  });
   424→
   425→  return sections.join('\n');
   426→}
   427→
   428→// ==================== TASK 3: FILE SYSTEM EXPORT HELPERS ====================
   429→
   430→/**
   431→ * Create ZIP archive from file array
   432→ *
   433→ * @param files Array of {path, content} objects
   434→ * @returns Blob ready for download
   435→ */
   436→export async function createMarkdownZip(
   437→  files: Array<{ path: string; content: string }>
   438→): Promise<Blob> {
   439→  const zip = new JSZip();
   440→
   441→  // Add files to ZIP
   442→  files.forEach(({ path, content }) => {
   443→    zip.file(path, content);
   444→  });
   445→
   446→  // Generate ZIP blob
   447→  const blob = await zip.generateAsync({ type: 'blob' });
   448→  log.info('Created ZIP archive', { fileCount: files.length });
   449→
   450→  return blob;
   451→}
   452→
   453→/**
   454→ * Build folder path from folder ID (recursively resolves parent folders)
   455→ *
   456→ * @param folderId Target folder ID (null = root)
   457→ * @param folders All folders
   458→ * @returns Path string (e.g., "notes/Work/Projects")
   459→ */
   460→export function buildFolderPath(
   461→  folderId: string | null,
   462→  folders: Folder[]
   463→): string {
   464→  if (!folderId) {
   465→    return 'notes';
   466→  }
   467→
   468→  const folder = folders.find((f) => f.id === folderId);
   469→  if (!folder) {
   470→    log.warn('Folder not found', { folderId });
   471→    return 'notes';
   472→  }
   473→
   474→  // Sanitize folder name
   475→  const sanitizedName = folder.name.replace(/[<>:"/\\|?*]/g, '').replace(/\s+/g, '-');
   476→
   477→  // Recursively build parent path
   478→  if (folder.parentId) {
   479→    const parentPath = buildFolderPath(folder.parentId, folders);
   480→    return `${parentPath}/${sanitizedName}`;
   481→  }
   482→
   483→  return `notes/${sanitizedName}`;
   484→}
   485→
   486→/**
   487→ * Download blob to user's filesystem
   488→ *
   489→ * @param blob Blob to download
   490→ * @param filename Download filename
   491→ */
   492→export function downloadBlob(blob: Blob, filename: string): void {
   493→  // Create temporary download link
   494→  const url = URL.createObjectURL(blob);
   495→  const a = document.createElement('a');
   496→  a.href = url;
   497→  a.download = filename;
   498→  a.style.display = 'none';
   499→
   500→  // Trigger download
   501→  document.body.appendChild(a);
   502→  a.click();
   503→
   504→  // Cleanup
   505→  setTimeout(() => {
   506→    document.body.removeChild(a);
   507→    URL.revokeObjectURL(url);
   508→  }, 100);
   509→
   510→  log.info('Download triggered', { filename });
   511→}
   512→
   513→/**
   514→ * Export notes with folder structure preserved
   515→ *
   516→ * @param notes All notes to export
   517→ * @param folders All folders
   518→ * @returns ZIP blob ready for download
   519→ */
   520→export async function exportNotesWithFolders(
   521→  notes: Note[],
   522→  folders: Folder[]
   523→): Promise<Blob> {
   524→  const files: Array<{ path: string; content: string }> = [];
   525→  const filenameMap = new Map<string, number>(); // Track duplicate filenames
   526→
   527→  // Convert all notes to markdown files
   528→  const allNotesMap = Object.fromEntries(notes.map((n) => [n.id, n]));
   529→
   530→  notes.forEach((note) => {
   531→    // Build folder path
   532→    const folderPath = buildFolderPath(note.folderId, folders);
   533→
   534→    // Get markdown filename
   535→    let filename = getMarkdownFilename(note);
   536→
   537→    // Handle duplicate filenames
   538→    const fullPath = `${folderPath}/${filename}`;
   539→    if (filenameMap.has(fullPath)) {
   540→      const count = filenameMap.get(fullPath)! + 1;
   541→      filenameMap.set(fullPath, count);
   542→      const baseName = filename.replace(/\.md$/, '');
   543→      filename = `${baseName}-${count}.md`;
   544→    } else {
   545→      filenameMap.set(fullPath, 1);
   546→    }
   547→
   548→    // Convert to markdown
   549→    const markdown = exportNoteToMarkdown(note, allNotesMap, folders);
   550→
   551→    files.push({
   552→      path: `${folderPath}/${filename}`,
   553→      content: markdown,
   554→    });
   555→  });
   556→
   557→  return createMarkdownZip(files);
   558→}
   559→
   560→/**
   561→ * Export all data (notes + tasks) with metadata
   562→ *
   563→ * @param notes All notes
   564→ * @param tasks All tasks
   565→ * @param folders All folders
   566→ * @returns ZIP blob with notes, tasks, and metadata.json
   567→ */
   568→export async function exportAllData(
   569→  notes: Note[],
   570→  tasks: Task[],
   571→  folders: Folder[]
   572→): Promise<Blob> {
   573→  const files: Array<{ path: string; content: string }> = [];
   574→  const allNotesMap = Object.fromEntries(notes.map((n) => [n.id, n]));
   575→  const filenameMap = new Map<string, number>();
   576→
   577→  // Export notes with folder structure
   578→  notes.forEach((note) => {
   579→    const folderPath = buildFolderPath(note.folderId, folders);
   580→    let filename = getMarkdownFilename(note);
   581→
   582→    // Handle duplicates
   583→    const fullPath = `${folderPath}/${filename}`;
   584→    if (filenameMap.has(fullPath)) {
   585→      const count = filenameMap.get(fullPath)! + 1;
   586→      filenameMap.set(fullPath, count);
   587→      const baseName = filename.replace(/\.md$/, '');
   588→      filename = `${baseName}-${count}.md`;
   589→    } else {
   590→      filenameMap.set(fullPath, 1);
   591→    }
   592→
   593→    const markdown = exportNoteToMarkdown(note, allNotesMap, folders);
   594→    files.push({
   595→      path: `${folderPath}/${filename}`,
   596→      content: markdown,
   597→    });
   598→  });
   599→
   600→  // Export tasks (grouped by status)
   601→  const statuses: Array<'backlog' | 'todo' | 'inprogress' | 'review' | 'done'> = [
   602→    'backlog',
   603→    'todo',
   604→    'inprogress',
   605→    'review',
   606→    'done',
   607→  ];
   608→
   609→  statuses.forEach((status) => {
   610→    const statusTasks = tasks.filter((t) => t.status === status);
   611→    if (statusTasks.length === 0) return;
   612→
   613→    const markdown = exportTasksToMarkdown(statusTasks);
   614→    files.push({
   615→      path: `tasks/by-status/${status}.md`,
   616→      content: markdown,
   617→    });
   618→  });
   619→
   620→  // Export all tasks in single file
   621→  const allTasksMarkdown = exportTasksToMarkdown(tasks);
   622→  files.push({
   623→    path: 'tasks/all-tasks.md',
   624→    content: allTasksMarkdown,
   625→  });
   626→
   627→  // Export metadata
   628→  const metadata = {
   629→    exportedAt: new Date().toISOString(),
   630→    noteCount: notes.length,
   631→    taskCount: tasks.length,
   632→    folderCount: folders.length,
   633→  };
   634→  files.push({
   635→    path: 'metadata.json',
   636→    content: JSON.stringify(metadata, null, 2),
