     1→/**
     2→ * Notes Page
     3→ *
     4→ * Main notes interface with 3-column layout:
     5→ * - Left: Folder tree + Notes list
     6→ * - Center: Rich text editor
     7→ * - Right: Note metadata (optional, collapsible)
     8→ */
     9→
    10→import React, { useEffect, useState, useRef, useMemo } from 'react';
    11→import { useSearchParams } from 'react-router-dom';
    12→import { motion, AnimatePresence } from 'framer-motion';
    13→import {
    14→  ChevronDown,
    15→  ChevronRight,
    16→  FolderOpen,
    17→  Folder,
    18→  FileText,
    19→  Edit2,
    20→  Trash2,
    21→  Pin,
    22→  Star,
    23→  Tag,
    24→  Check,
    25→  Download,
    26→  Loader2,
    27→  FileDown,
    28→  Sparkles,
    29→} from 'lucide-react';
    30→import { useNotesStore } from '../stores/useNotesStore';
    31→import { useFoldersStore } from '../stores/useFoldersStore';
    32→import { NotesEditor, NotesEditorEmpty } from '../widgets/NotesEditor';
    33→import { ConfirmDialog } from '../components/ConfirmDialog';
    34→import { PromptDialog } from '../components/PromptDialog';
    35→import { PageHeader } from '../components/PageHeader';
    36→import { useUndoStore } from '../stores/useUndoStore';
    37→import { exportNoteToMarkdown } from '../services/noteExport';
    38→import { exportNoteToPDF } from '../services/notePdfExport';
    39→import { logger } from '../services/logger';
    40→import type { Note } from '../types/notes';
    41→import { DailyNotesCalendar } from '../components/DailyNotesCalendar';
    42→import { useSettingsStore } from '../stores/useSettingsStore';
    43→import { Calendar as CalendarIcon } from 'lucide-react';
    44→import { TagFilter } from '../components/TagFilter';
    45→import { TagManager } from '../components/TagManager';
    46→import { tagMatchesFilter } from '../utils/tagHierarchy';
    47→import { TemplateLibrary } from '../components/TemplateLibrary';
    48→import { substituteTemplateVariables, extractTemplateVariables } from '../utils/templateVariables';
    49→import type { NoteTemplate } from '../types/notes';
    50→
    51→const log = logger.module('Notes');
    52→
    53→/**
    54→ * Recursive Folder Tree Node Component
    55→ */
    56→interface FolderTreeNodeProps {
    57→  node: any;
    58→  depth: number;
    59→  activeFolderId: string | null;
    60→  expandedFolderIds: Set<string>;
    61→  onSelect: (id: string) => void;
    62→  onToggleExpanded: (id: string) => void;
    63→  onDelete: (id: string, name: string) => void;
    64→  onRename: (id: string, name: string) => void;
    65→  getFolderNoteCount: (id: string) => number;
    66→}
    67→
    68→const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
    69→  node,
    70→  depth,
    71→  activeFolderId,
    72→  expandedFolderIds,
    73→  onSelect,
    74→  onToggleExpanded,
    75→  onDelete,
    76→  onRename,
    77→  getFolderNoteCount,
    78→}) => {
    79→  const isExpanded = expandedFolderIds.has(node.id);
    80→  const hasChildren = node.children && node.children.length > 0;
    81→  const noteCount = getFolderNoteCount(node.id);
    82→
    83→  return (
    84→    <div>
    85→      <div
    86→        className={`group relative rounded-lg transition-all duration-standard ${
    87→          activeFolderId === node.id
    88→            ? 'bg-accent-cyan bg-opacity-10 dark:bg-accent-magenta dark:bg-opacity-10'
    89→            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated hover:shadow-sm'
    90→        }`}
    91→        style={{ paddingLeft: `${depth * 16}px` }}
    92→      >
    93→        <div className="flex items-center">
    94→          {/* Expand/collapse button */}
    95→          {hasChildren && (
    96→            <button
    97→              onClick={(e) => {
    98→                e.stopPropagation();
    99→                onToggleExpanded(node.id);
   100→              }}
   101→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
   102→            >
   103→              {isExpanded ? (
   104→                <ChevronDown className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   105→              ) : (
   106→                <ChevronRight className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   107→              )}
   108→            </button>
   109→          )}
   110→          {!hasChildren && <span className="w-6" />}
   111→
   112→          {/* Folder button */}
   113→          <button
   114→            onClick={() => onSelect(node.id)}
   115→            className={`flex-1 text-left px-3 py-2 transition-all duration-standard flex items-center gap-2 ${
   116→              activeFolderId === node.id
   117→                ? 'text-accent-cyan dark:text-accent-magenta font-medium'
   118→                : 'text-text-light-secondary dark:text-text-dark-secondary group-hover:text-text-light-primary dark:group-hover:text-text-dark-primary'
   119→            }`}
   120→          >
   121→            {hasChildren ? (
   122→              isExpanded ? (
   123→                <FolderOpen className="w-4 h-4" />
   124→              ) : (
   125→                <Folder className="w-4 h-4" />
   126→              )
   127→            ) : (
   128→              <FileText className="w-4 h-4" />
   129→            )}
   130→            <span>{node.name}</span>
   131→            {noteCount > 0 && (
   132→              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   133→                ({noteCount})
   134→              </span>
   135→            )}
   136→          </button>
   137→
   138→          {/* Action buttons */}
   139→          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity">
   140→            <button
   141→              onClick={(e) => {
   142→                e.stopPropagation();
   143→                onRename(node.id, node.name);
   144→              }}
   145→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
   146→              title="Rename folder"
   147→            >
   148→              <Edit2 className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   149→            </button>
   150→            <button
   151→              onClick={(e) => {
   152→                e.stopPropagation();
   153→                onDelete(node.id, node.name);
   154→              }}
   155→              className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600 transition-colors"
   156→              title="Delete folder"
   157→            >
   158→              <Trash2 className="w-4 h-4" />
   159→            </button>
   160→          </div>
   161→        </div>
   162→      </div>
   163→
   164→      {/* Children */}
   165→      {isExpanded && hasChildren && (
   166→        <div className="ml-4">
   167→          {node.children.map((child: any) => (
   168→            <FolderTreeNode
   169→              key={child.id}
   170→              node={child}
   171→              depth={depth + 1}
   172→              activeFolderId={activeFolderId}
   173→              expandedFolderIds={expandedFolderIds}
   174→              onSelect={onSelect}
   175→              onToggleExpanded={onToggleExpanded}
   176→              onDelete={onDelete}
   177→              onRename={onRename}
   178→              getFolderNoteCount={getFolderNoteCount}
   179→            />
   180→          ))}
   181→        </div>
   182→      )}
   183→    </div>
   184→  );
   185→};
   186→
   187→/**
   188→ * Folder Sidebar Component (Simplified for MVP)
   189→ */
   190→const FolderSidebar: React.FC<{
   191→  activeTags: string[];
   192→  onAddTag: (tag: string) => void;
   193→  onRemoveTag: (tag: string) => void;
   194→  onClearAllTags: () => void;
   195→  onOpenTagManager: () => void;
   196→}> = ({ activeTags, onAddTag, onRemoveTag, onClearAllTags, onOpenTagManager }) => {
   197→  // Get raw folders object (stable reference unless folders change)
   198→  const foldersObj = useFoldersStore((state) => state.folders);
   199→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   200→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   201→  const createFolder = useFoldersStore((state) => state.createFolder);
   202→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
   203→  const updateFolder = useFoldersStore((state) => state.updateFolder);
   204→  const notesObj = useNotesStore((state) => state.notes);
   205→  const searchNotes = useNotesStore((state) => state.searchNotes);
   206→
   207→  // Dialog state
   208→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
   209→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
   210→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
   211→  const [selectedFolderName, setSelectedFolderName] = useState('');
   212→
   213→  // Search state
   214→  const [searchQuery, setSearchQuery] = useState('');
   215→  const searchInputRef = useRef<HTMLInputElement>(null);
   216→
   217→  // Keyboard shortcut for search (Cmd+K)
   218→  useEffect(() => {
   219→    const handleKeyDown = (e: KeyboardEvent) => {
   220→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   221→        e.preventDefault();
   222→        searchInputRef.current?.focus();
   223→      }
   224→    };
   225→
   226→    window.addEventListener('keydown', handleKeyDown);
   227→    return () => window.removeEventListener('keydown', handleKeyDown);
   228→  }, []);
   229→
   230→  // Get tree structure for nested folders
   231→  const getTree = useFoldersStore((state) => state.getTree);
   232→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
   233→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
   234→
   235→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
   236→
   237→  // Get note count for a folder
   238→  const getFolderNoteCount = (folderId: string) => {
   239→    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
   240→  };
   241→
   242→  // Handle folder deletion
   243→  const handleDeleteFolder = (folderId: string, folderName: string) => {
   244→    setSelectedFolderId(folderId);
   245→    setSelectedFolderName(folderName);
   246→    setDeleteDialogOpen(true);
   247→  };
   248→
   249→  const confirmDeleteFolder = () => {
   250→    if (!selectedFolderId) return;
   251→
   252→    // Save folder and notes for undo
   253→    const folderToDelete = foldersObj[selectedFolderId];
   254→    if (!folderToDelete) {
   255→      log.warn('Folder not found', { folderId: selectedFolderId });
   256→      return;
   257→    }
   258→
   259→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   260→    const noteCount = notesToDelete.length;
   261→
   262→    // Delete all notes in this folder (without undo since folder undo will handle it)
   263→    // We need to temporarily bypass the undo system for individual notes
   264→    notesToDelete.forEach(note => {
   265→      // Call the store action directly without triggering undo
   266→      useNotesStore.setState((state) => {
   267→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   268→        return {
   269→          notes: remainingNotes,
   270→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   271→        };
   272→      });
   273→    });
   274→
   275→    // Delete the folder
   276→    deleteFolder(selectedFolderId);
   277→
   278→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   279→
   280→    // Add undo action to restore folder AND notes
   281→    useUndoStore.getState().addUndoAction(
   282→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   283→      () => {
   284→        // Restore the folder
   285→        useFoldersStore.setState((state) => ({
   286→          folders: {
   287→            ...state.folders,
   288→            [folderToDelete.id]: folderToDelete,
   289→          },
   290→        }));
   291→
   292→        // Restore all notes
   293→        useNotesStore.setState((state) => {
   294→          const restoredNotes = { ...state.notes };
   295→          notesToDelete.forEach(note => {
   296→            restoredNotes[note.id] = note;
   297→          });
   298→          return {
   299→            notes: restoredNotes,
   300→          };
   301→        });
   302→
   303→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   304→      }
   305→    );
   306→  };
   307→
   308→  // Handle folder rename
   309→  const handleRenameFolder = (folderId: string, currentName: string) => {
   310→    setSelectedFolderId(folderId);
   311→    setSelectedFolderName(currentName);
   312→    setRenameDialogOpen(true);
   313→  };
   314→
   315→  const confirmRenameFolder = (newName: string) => {
   316→    if (!selectedFolderId || !newName.trim()) return;
   317→    updateFolder(selectedFolderId, { name: newName.trim() });
   318→  };
   319→
   320→  return (
   321→    <div className="p-4 flex flex-col max-h-[40%] overflow-hidden border-b border-border-light dark:border-border-dark">
   322→      {/* Folders header */}
   323→      <div className="flex items-center justify-between mb-4 flex-shrink-0">
   324→        <h3 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">Folders</h3>
   325→        <button
   326→          onClick={() => createFolder()}
   327→          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors duration-150 font-medium"
   328→          title="New Folder"
   329→        >
   330→          + Folder
   331→        </button>
   332→      </div>
   333→
   334→      {/* Search Input */}
   335→      <div className="px-3 py-2">
   336→        <input
   337→          type="text"
   338→          placeholder="Search notes... (Cmd+K)"
   339→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   340→                     bg-surface-light dark:bg-surface-dark
   341→                     text-text-light-primary dark:text-text-dark-primary
   342→                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
   343→                     focus:outline-none focus:ring-2 focus:ring-accent-blue transition-all"
   344→          value={searchQuery}
   345→          onChange={(e) => setSearchQuery(e.target.value)}
   346→          ref={searchInputRef}
   347→        />
   348→      </div>
   349→
   350→      {/* All Notes (root level) */}
   351→      {!searchQuery.trim() && (
   352→        <button
   353→          onClick={() => setActiveFolder(null)}
   354→          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center gap-2 text-base ${
   355→            activeFolderId === null
   356→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
   357→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   358→          }`}
   359→        >
   360→          <FolderOpen className="w-4 h-4" />
   361→          All Notes
   362→        </button>
   363→      )}
   364→
   365→      {/* Search Results OR Folder list */}
   366→      {searchQuery.trim() ? (
   367→        /* Search Results */
   368→        <div className="px-3 overflow-y-auto flex-1">
   369→          <h3 className="text-sm font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
   370→            {searchNotes(searchQuery).length} results for "{searchQuery}"
   371→          </h3>
   372→          <div className="space-y-2">
   373→            {searchNotes(searchQuery).map((note) => (
   374→              <div
   375→                key={note.id}
   376→                onClick={() => {
   377→                  setSearchQuery(''); // Clear search
   378→                  // Note will be selected via the NotesList component
   379→                }}
   380→                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   381→              >
   382→                <div className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   383→                  {note.title || 'Untitled'}
   384→                </div>
   385→                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
   386→                  {note.contentText?.slice(0, 150)}...
   387→                </div>
   388→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   389→                  {new Date(note.updatedAt).toLocaleDateString()}
   390→                </div>
   391→              </div>
   392→            ))}
   393→            {searchNotes(searchQuery).length === 0 && (
   394→              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-8">
   395→                No notes found for "{searchQuery}"
   396→              </div>
   397→            )}
   398→          </div>
   399→        </div>
   400→      ) : (
   401→        /* Folder tree - Scrollable */
   402→        <div className="space-y-1 overflow-y-auto flex-1">
   403→          {folderTree.map((node) => (
   404→            <FolderTreeNode
   405→              key={node.id}
   406→              node={node}
   407→              depth={0}
   408→              activeFolderId={activeFolderId}
   409→              expandedFolderIds={expandedFolderIds}
   410→              onSelect={setActiveFolder}
   411→              onToggleExpanded={toggleExpanded}
   412→              onDelete={handleDeleteFolder}
   413→              onRename={handleRenameFolder}
   414→              getFolderNoteCount={getFolderNoteCount}
   415→            />
   416→          ))}
   417→
   418→          {/* Empty state */}
   419→          {folderTree.length === 0 && (
   420→            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
   421→              No folders yet
   422→            </div>
   423→          )}
   424→        </div>
   425→      )}
   426→
   427→      {/* Tag Filter Section */}
   428→      <div className="px-4 py-3 border-t border-border-light dark:border-border-dark">
   429→        <TagFilter
   430→          activeTags={activeTags}
   431→          onAddTag={onAddTag}
   432→          onRemoveTag={onRemoveTag}
   433→          onClearAll={onClearAllTags}
   434→        />
   435→        <button
   436→          onClick={onOpenTagManager}
   437→          className="w-full mt-3 px-3 py-2 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-colors"
   438→        >
   439→          Manage Tags
   440→        </button>
   441→      </div>
   442→
   443→      {/* Delete Folder Confirmation Dialog */}
   444→      <ConfirmDialog
   445→        isOpen={deleteDialogOpen}
   446→        onClose={() => setDeleteDialogOpen(false)}
   447→        onConfirm={confirmDeleteFolder}
   448→        title="Delete Folder"
   449→        message={`Delete folder "${selectedFolderName}"? This will also delete ${selectedFolderId ? getFolderNoteCount(selectedFolderId) : 0} note(s) inside.`}
   450→        confirmText="Delete"
   451→        variant="danger"
   452→      />
   453→
   454→      {/* Rename Folder Prompt Dialog */}
   455→      <PromptDialog
   456→        isOpen={renameDialogOpen}
   457→        onClose={() => setRenameDialogOpen(false)}
   458→        onConfirm={confirmRenameFolder}
   459→        title="Rename Folder"
   460→        message="Enter a new name for this folder:"
   461→        defaultValue={selectedFolderName}
   462→        placeholder="Folder name"
   463→        confirmText="Rename"
   464→      />
   465→    </div>
   466→  );
   467→};
   468→
   469→/**
   470→ * Note List Item Component
   471→ */
   472→const NoteListItem: React.FC<{
   473→  note: Note;
   474→  isActive: boolean;
   475→  isSelectionMode?: boolean;
   476→  isSelected?: boolean;
   477→  onToggleSelection?: (id: string) => void;
   478→}> = ({
   479→  note,
   480→  isActive,
   481→  isSelectionMode = false,
   482→  isSelected = false,
   483→  onToggleSelection,
   484→}) => {
   485→  const setActiveNote = useNotesStore((state) => state.setActiveNote);
   486→  const deleteNote = useNotesStore((state) => state.deleteNote);
   487→  const togglePin = useNotesStore((state) => state.togglePin);
   488→  const toggleFavorite = useNotesStore((state) => state.toggleFavorite);
   489→  const tagColors = useSettingsStore((state) => state.tagColors);
   490→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
   491→  const [isExporting, setIsExporting] = useState(false);
   492→  const [exportSuccess, setExportSuccess] = useState<string | null>(null);
   493→
   494→  // Handle PDF export with loading state
   495→  const handlePDFExport = async (e: React.MouseEvent) => {
   496→    e.stopPropagation();
   497→    setIsExporting(true);
   498→    try {
   499→      await exportNoteToPDF(note, (filename) => {
   500→        setExportSuccess(filename);
   501→        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
   502→      });
   503→    } catch (error) {
   504→      log.error('PDF export failed', { error });
   505→    } finally {
   506→      setIsExporting(false);
   507→    }
   508→  };
   509→
   510→  // Format date
   511→  const formatDate = (date: Date) => {
   512→    const now = new Date();
   513→    const diff = now.getTime() - new Date(date).getTime();
   514→    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   515→
   516→    if (days === 0) return 'Today';
   517→    if (days === 1) return 'Yesterday';
   518→    if (days < 7) return `${days} days ago`;
   519→    return new Date(date).toLocaleDateString();
   520→  };
   521→
   522→  // First line of content
   523→  const preview = note.contentText.split('\n')[0] || 'No content';
   524→
   525→  return (
   526→    <div
   527→      className={`group relative p-4 rounded-lg cursor-pointer transition-all duration-standard hover:scale-[1.01] ${
   528→        isActive
   529→          ? 'bg-accent-cyan bg-opacity-10 dark:bg-accent-magenta dark:bg-opacity-10 border-l-4 border-accent-cyan dark:border-accent-magenta shadow-sm'
   530→          : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated border-l-4 border-transparent hover:shadow-sm'
   531→      }`}
   532→      onClick={() => setActiveNote(note.id)}
   533→    >
   534→      {/* Export Success Notification */}
   535→      {exportSuccess && (
   536→        <div className="absolute -top-8 left-0 right-0 bg-green-500 text-white text-xs py-1 px-2 rounded shadow-lg z-10 text-center flex items-center justify-center gap-1">
   537→          <Check className="w-3 h-3" />
   538→          Exported: {exportSuccess}
   539→        </div>
   540→      )}
   541→
   542→      {/* Main layout: Vertical actions on left + Content on right */}
   543→      <div className="flex items-start gap-2">
   544→        {/* Vertical action column - appears on left side on hover */}
   545→        <div className="flex flex-col gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-200 shrink-0 w-6">
   546→          <button
   547→            onClick={(e) => {
   548→              e.stopPropagation();
   549→              exportNoteToMarkdown(note);
   550→            }}
