   693→const NotesList: React.FC<{
   694→  activeTags: string[];
   695→  onOpenTemplateLibrary: () => void;
   696→}> = ({ activeTags, onOpenTemplateLibrary }) => {
   697→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   698→  // Get raw notes and store config (stable references)
   699→  const notesObj = useNotesStore((state) => state.notes);
   700→  const sortConfig = useNotesStore((state) => state.sortConfig);
   701→  const filter = useNotesStore((state) => state.filter);
   702→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   703→  const createNote = useNotesStore((state) => state.createNote);
   704→  const bulkAddTag = useNotesStore((state) => state.bulkAddTag);
   705→  const bulkRemoveTag = useNotesStore((state) => state.bulkRemoveTag);
   706→
   707→  // Bulk operations state
   708→  const [selectionMode, setSelectionMode] = useState(false);
   709→  const [selectedNoteIds, setSelectedNoteIds] = useState<Set<string>>(new Set());
   710→  const [bulkTagDialogOpen, setBulkTagDialogOpen] = useState(false);
   711→  const [bulkTagAction, setBulkTagAction] = useState<'add' | 'remove' | null>(null);
   712→  const [bulkTagValue, setBulkTagValue] = useState('');
   713→
   714→  // Bulk operations handlers
   715→  const toggleSelectionMode = () => {
   716→    setSelectionMode(!selectionMode);
   717→    if (selectionMode) {
   718→      setSelectedNoteIds(new Set());
   719→    }
   720→  };
   721→
   722→  const toggleNoteSelection = (noteId: string) => {
   723→    setSelectedNoteIds((prev) => {
   724→      const next = new Set(prev);
   725→      if (next.has(noteId)) {
   726→        next.delete(noteId);
   727→      } else {
   728→        next.add(noteId);
   729→      }
   730→      return next;
   731→    });
   732→  };
   733→
   734→  const selectAll = () => {
   735→    const allIds = notes.map((n) => n.id);
   736→    setSelectedNoteIds(new Set(allIds));
   737→  };
   738→
   739→  const deselectAll = () => {
   740→    setSelectedNoteIds(new Set());
   741→  };
   742→
   743→  const handleBulkAddTag = () => {
   744→    setBulkTagAction('add');
   745→    setBulkTagDialogOpen(true);
   746→  };
   747→
   748→  const handleBulkRemoveTag = () => {
   749→    setBulkTagAction('remove');
   750→    setBulkTagDialogOpen(true);
   751→  };
   752→
   753→  const confirmBulkTagAction = (value: string) => {
   754→    if (!value.trim() || selectedNoteIds.size === 0) return;
   755→
   756→    if (bulkTagAction === 'add') {
   757→      bulkAddTag(Array.from(selectedNoteIds), value.trim());
   758→    } else if (bulkTagAction === 'remove') {
   759→      bulkRemoveTag(Array.from(selectedNoteIds), value.trim());
   760→    }
   761→
   762→    // Clear selection and close dialog
   763→    setBulkTagDialogOpen(false);
   764→    setBulkTagValue('');
   765→    setSelectedNoteIds(new Set());
   766→    setSelectionMode(false);
   767→  };
   768→
   769→  // Compute filtered/sorted notes with useMemo
   770→  const notes = useMemo(() => {
   771→    // Filter by folder
   772→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   773→    let filtered = activeFolderId === null
   774→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   775→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   776→
   777→    // Filter by tags (AND logic - note must have ALL selected tags or their children)
   778→    if (activeTags.length > 0) {
   779→      filtered = filtered.filter((note) =>
   780→        activeTags.every((filterTag) =>
   781→          note.tags.some((noteTag) => tagMatchesFilter(noteTag, filterTag))
   782→        )
   783→      );
   784→    }
   785→
   786→    // Apply filter (archived, pinned, favorites, etc.)
   787→    switch (filter) {
   788→      case 'favorites':
   789→        filtered = filtered.filter((note) => note.isFavorite);
   790→        break;
   791→      case 'pinned':
   792→        filtered = filtered.filter((note) => note.isPinned);
   793→        break;
   794→      case 'archived':
   795→        filtered = filtered.filter((note) => note.isArchived);
   796→        break;
   797→      case 'unarchived':
   798→        filtered = filtered.filter((note) => !note.isArchived);
   799→        break;
   800→    }
   801→
   802→    // Sort notes
   803→    const sorted = [...filtered].sort((a, b) => {
   804→      let comparison = 0;
   805→      switch (sortConfig.field) {
   806→        case 'title':
   807→          comparison = a.title.localeCompare(b.title);
   808→          break;
   809→        case 'createdAt':
   810→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   811→          break;
   812→        case 'updatedAt':
   813→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   814→          break;
   815→      }
   816→      return sortConfig.order === 'asc' ? comparison : -comparison;
   817→    });
   818→
   819→    // Always pin pinned notes to top
   820→    return sorted.sort((a, b) => {
   821→      if (a.isPinned && !b.isPinned) return -1;
   822→      if (!a.isPinned && b.isPinned) return 1;
   823→      return 0;
   824→    });
   825→  }, [notesObj, activeFolderId, sortConfig, filter, activeTags]);
   826→
   827→  return (
   828→    <div className="flex-1 overflow-y-auto">
   829→      <div className="bento-card p-4 m-3">
   830→        {/* Notes header */}
   831→        <div className="flex items-center justify-between mb-4">
   832→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   833→            Notes ({notes.length})
   834→          </h3>
   835→          <div className="flex items-center gap-2">
   836→            <button
   837→              onClick={toggleSelectionMode}
   838→              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
   839→                selectionMode
   840→                  ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   841→                  : 'border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   842→              }`}
   843→            >
   844→              {selectionMode ? 'Cancel Selection' : 'Select Notes'}
   845→            </button>
   846→            <button
   847→              onClick={onOpenTemplateLibrary}
   848→              className="px-3 py-1.5 bg-accent-purple text-white rounded-lg hover:bg-accent-purple-hover transition-all duration-200 text-sm font-medium flex items-center gap-1"
   849→              title="Create note from template"
   850→            >
   851→              <Sparkles className="w-4 h-4" />
   852→              From Template
   853→            </button>
   854→            <button
   855→              onClick={() => createNote({ folderId: activeFolderId })}
   856→              className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   857→            >
   858→              + New Note
   859→            </button>
   860→          </div>
   861→        </div>
   862→
   863→        {/* Bulk Operations Toolbar */}
   864→        {selectionMode && selectedNoteIds.size > 0 && (
   865→          <div className="mb-4 p-3 rounded-lg bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue/30">
   866→            <div className="flex items-center justify-between">
   867→              <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   868→                {selectedNoteIds.size} note{selectedNoteIds.size !== 1 ? 's' : ''} selected
   869→              </span>
   870→              <div className="flex items-center gap-2">
   871→                <button
   872→                  onClick={selectAll}
   873→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   874→                >
   875→                  Select All
   876→                </button>
   877→                <button
   878→                  onClick={deselectAll}
   879→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   880→                >
   881→                  Deselect All
   882→                </button>
   883→                <button
   884→                  onClick={handleBulkAddTag}
   885→                  className="px-3 py-1 text-xs font-medium rounded bg-accent-blue text-white hover:bg-accent-blue-hover transition-colors"
   886→                >
   887→                  Add Tag
   888→                </button>
   889→                <button
   890→                  onClick={handleBulkRemoveTag}
   891→                  className="px-3 py-1 text-xs font-medium rounded bg-red-500/20 text-red-500 hover:bg-red-500/30 transition-colors"
   892→                >
   893→                  Remove Tag
   894→                </button>
   895→              </div>
   896→            </div>
   897→          </div>
   898→        )}
   899→
   900→      {/* Notes list */}
   901→      <div className="space-y-3">
   902→        {notes.map((note) => (
   903→          <NoteListItem
   904→            key={note.id}
   905→            note={note}
   906→            isActive={note.id === activeNoteId}
   907→            isSelectionMode={selectionMode}
   908→            isSelected={selectedNoteIds.has(note.id)}
   909→            onToggleSelection={toggleNoteSelection}
   910→          />
   911→        ))}
   912→      </div>
   913→
   914→      {/* Empty state */}
   915→      {notes.length === 0 && (
   916→        <div className="text-center py-16 animate-fade-in">
   917→          <div className="flex justify-center mb-6">
   918→            <div className="p-6 bg-gradient-to-br from-accent-magenta/10 to-accent-cyan/10 dark:from-accent-cyan/10 dark:to-accent-magenta/10 rounded-2xl">
   919→              <FileText className="w-16 h-16 text-accent-cyan dark:text-accent-magenta" />
   920→            </div>
   921→          </div>
   922→          <h3 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-3">
   923→            {activeTags.length > 0 ? 'No notes match these tags' : 'No notes in this folder'}
   924→          </h3>
   925→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2 max-w-sm mx-auto">
   926→            {activeTags.length > 0
   927→              ? 'Try removing some tags or create a new note'
   928→              : 'Start capturing your thoughts, ideas, and knowledge'}
   929→          </p>
   930→          <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary mb-6">
   931→            Tip: Use <kbd className="px-2 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded text-xs font-mono">Cmd+N</kbd> to create notes quickly
   932→          </p>
   933→          <button
   934→            onClick={() => createNote({ folderId: activeFolderId })}
   935→            className="px-6 py-3 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-standard font-medium inline-flex items-center gap-2"
   936→          >
   937→            <FileText className="w-5 h-5" />
   938→            Create Your First Note
   939→          </button>
   940→        </div>
   941→      )}
   942→      </div>
   943→
   944→      {/* Bulk Tag Dialog */}
   945→      {bulkTagDialogOpen && (
   946→        <PromptDialog
