   957→              : `Enter tag name to remove from ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
   958→          }
   959→          defaultValue={bulkTagValue}
   960→          placeholder="Tag name"
   961→          confirmText={bulkTagAction === 'add' ? 'Add Tag' : 'Remove Tag'}
