   981→  const [blockId, setBlockId] = useState<string | undefined>();
   982→
   983→  // Tag filtering state
   984→  const [activeTags, setActiveTags] = useState<string[]>([]);
   985→  const [showTagManager, setShowTagManager] = useState(false);
   986→
   987→  // Template Library state
   988→  const [showTemplateLibrary, setShowTemplateLibrary] = useState(false);
   989→  const [showTitlePrompt, setShowTitlePrompt] = useState(false);
   990→  const [selectedTemplate, setSelectedTemplate] = useState<NoteTemplate | null>(null);
   991→  const [titleInput, setTitleInput] = useState('');
   992→
   993→  // Get store actions
   994→  const createNote = useNotesStore((state) => state.createNote);
   995→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   996→
   997→  const handleAddTag = (tag: string) => {
   998→    if (!activeTags.includes(tag)) {
   999→      setActiveTags([...activeTags, tag]);
  1000→    }
  1001→  };
  1002→
  1003→  const handleRemoveTag = (tag: string) => {
  1004→    setActiveTags(activeTags.filter((t) => t !== tag));
  1005→  };
  1006→
  1007→  const handleClearAllTags = () => {
  1008→    setActiveTags([]);
  1009→  };
  1010→
  1011→  // Template selection handlers
  1012→  const handleSelectTemplate = (template: NoteTemplate) => {
  1013→    // Check if template contains {title} variable
  1014→    const variables = extractTemplateVariables(template.description);
  1015→    if (variables.includes('title')) {
  1016→      // Prompt user for title
  1017→      setSelectedTemplate(template);
  1018→      setTitleInput('');
  1019→      setShowTitlePrompt(true);
  1020→      setShowTemplateLibrary(false);
  1021→    } else {
  1022→      // Create note immediately with variable substitution
  1023→      createNoteFromTemplate(template);
  1024→    }
  1025→  };
  1026→
  1027→  const createNoteFromTemplate = (template: NoteTemplate, customTitle?: string) => {
  1028→    // Substitute template variables
  1029→    const context = {
  1030→      title: customTitle,
  1031→      userName: 'User', // Could be fetched from settings in future
  1032→    };
  1033→    const processedContent = substituteTemplateVariables(template.description, context);
  1034→
  1035→    // Create note with template content and tags
  1036→    const newNote = createNote({
  1037→      folderId: activeFolderId,
  1038→      title: customTitle || template.name,
  1039→      contentText: processedContent,
  1040→      tags: template.defaultTags || [],
  1041→      icon: template.icon,
  1042→    });
  1043→
  1044→    log.info('Created note from template', {
  1045→      templateId: template.id,
  1046→      noteId: newNote.id,
  1047→      title: newNote.title,
  1048→    });
  1049→  };
  1050→
  1051→  const handleConfirmTitle = (title: string) => {
  1052→    if (selectedTemplate && title.trim()) {
  1053→      createNoteFromTemplate(selectedTemplate, title.trim());
  1054→      setShowTitlePrompt(false);
  1055→      setSelectedTemplate(null);
  1056→      setTitleInput('');
  1057→    }
  1058→  };
  1059→
  1060→  const handleCancelTitle = () => {
  1061→    setShowTitlePrompt(false);
  1062→    setSelectedTemplate(null);
  1063→    setTitleInput('');
  1064→  };
  1065→
  1066→  useEffect(() => {
  1067→    document.title = 'Notes - Neuman Brain';
  1068→    log.debug('Notes page loaded');
  1069→  }, []);
  1070→
  1071→  // Handle ?daily=true query parameter to open today's daily note
  1072→  useEffect(() => {
  1073→    if (searchParams.get('daily') === 'true' && dailyNotesEnabled) {
  1074→      const today = new Date();
  1075→      getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
  1076→      // Remove the query parameter after handling it
  1077→      searchParams.delete('daily');
  1078→      setSearchParams(searchParams, { replace: true });
  1079→    }
  1080→  }, [searchParams, dailyNotesEnabled, getOrCreateDailyNote, setSearchParams]);
  1081→
  1082→  // Extract block ID from URL hash (#block-id)
  1083→  useEffect(() => {
  1084→    const handleHashChange = () => {
  1085→      const hash = window.location.hash;
  1086→      if (hash && hash.startsWith('#')) {
  1087→        const id = hash.substring(1); // Remove # prefix
  1088→        setBlockId(id);
  1089→      } else {
  1090→        setBlockId(undefined);
  1091→      }
  1092→    };
  1093→
  1094→    // Set initial block ID
  1095→    handleHashChange();
  1096→
  1097→    // Listen for hash changes
  1098→    window.addEventListener('hashchange', handleHashChange);
  1099→    return () => window.removeEventListener('hashchange', handleHashChange);
  1100→  }, []);
  1101→
  1102→  // Handle sidebar resize
  1103→  const handleMouseDown = (e: React.MouseEvent) => {
  1104→    e.preventDefault();
  1105→    setIsResizing(true);
  1106→  };
  1107→
