  1109→    const handleMouseMove = (e: MouseEvent) => {
  1110→      if (!isResizing) return;
  1111→      const newWidth = Math.max(200, Math.min(500, e.clientX - 72)); // 72px is sidebar offset
  1112→      setSidebarWidth(newWidth);
  1113→    };
  1114→
  1115→    const handleMouseUp = () => {
