  1117→    };
  1118→
  1119→    if (isResizing) {
  1120→      document.addEventListener('mousemove', handleMouseMove);
  1121→      document.addEventListener('mouseup', handleMouseUp);
  1122→      document.body.style.cursor = 'ew-resize';
  1123→      document.body.style.userSelect = 'none';
  1124→    }
  1125→
  1126→    return () => {
  1127→      document.removeEventListener('mousemove', handleMouseMove);
  1128→      document.removeEventListener('mouseup', handleMouseUp);
  1129→      document.body.style.cursor = '';
  1130→      document.body.style.userSelect = '';
  1131→    };
  1132→  }, [isResizing]);
  1133→
  1134→  return (
  1135→    <div className="notes-page">
  1136→      {/* Page Header */}
  1137→      <PageHeader />
  1138→
  1139→      {/* Notes Content */}
  1140→      <div className="h-[calc(100vh-280px)] flex relative">
  1141→        {/* Left Sidebar - Folders + Notes List */}
  1142→        <AnimatePresence>
  1143→        {!isSidebarCollapsed && (
  1144→          <motion.div
  1145→            ref={sidebarRef}
  1146→            initial={{ width: 0, opacity: 0 }}
