    }

    const taskText = count === 1 ? 'task' : 'tasks';
    const scopeLabel =
      exportScope === 'column'
        ? ` from ${getColumnName(selectedColumn)}`
        : ' from all columns';
    return `${count} ${taskText} will be exported${scopeLabel}`;
  };

