              </div>
            </label>
          </div>

          {/* Preview */}
          <div className="p-4 rounded-lg bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark">
            <div className="flex items-center gap-2 text-sm">
